import{_ as t,o as l,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260511/F02_營業現金流與獲利品質.md","filePath":"審計報告庫/財務審計/6261_久元/20260511/F02_營業現金流與獲利品質.md"}'),r={name:"審計報告庫/財務審計/6261_久元/20260511/F02_營業現金流與獲利品質.md"};function e(n,a,s,h,d,F){return l(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="f02-營業現金流與獲利品質-財務審計專家報告" tabindex="-1">F02: 營業現金流與獲利品質 - 財務審計專家報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-財務審計專家報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - 財務審計專家報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</p></blockquote><h2 id="🎯-專家直斷-74-字" tabindex="-1">🎯 專家直斷（74 字） <a class="header-anchor" href="#🎯-專家直斷-74-字" aria-label="Permalink to &quot;🎯 專家直斷（74 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CFO/NI 連續 3 年 &gt;265%（2024 年達 593%），獲利含金量極高。但 NI 波動大（2024 年 -37.6%），FCF 2025 轉負（-4.05 億），現金流強但利潤品質轉弱。</li></ul><h2 id="📊-診斷評級-140-字" tabindex="-1">📊 診斷評級（140 字） <a class="header-anchor" href="#📊-診斷評級-140-字" aria-label="Permalink to &quot;📊 診斷評級（140 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：CFO 5.19 億（2023）→ 7.22 億（2024）→ 6.64 億（2025）；CFO/NI 265%→593%→351%；FCF 3.88 億→2.39 億→-4.05 億；年折舊約 5.02 億（2024）。</li><li><strong>診斷見解</strong>：CFO 長期大幅超越 NI，主因每年約 5 億折舊為非現金費用。獲利真實無虞——營運資金管理得當（2024 年應收減少回收 0.72 億、應付增加 2.38 億）。但 2025 年 FCF 轉負（-4.05 億）因大額資本支出，需關注 CapEx 後續回報。</li></ul><h2 id="🔍-答詢詳解-425-字" tabindex="-1">🔍 答詢詳解（425 字） <a class="header-anchor" href="#🔍-答詢詳解-425-字" aria-label="Permalink to &quot;🔍 答詢詳解（425 字）&quot;">​</a></h2><h3 id="一、獲利含金量測試-cfo-ni-ratio" tabindex="-1">一、獲利含金量測試（CFO/NI Ratio） <a class="header-anchor" href="#一、獲利含金量測試-cfo-ni-ratio" aria-label="Permalink to &quot;一、獲利含金量測試（CFO/NI Ratio）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：CFO/NI 比值 265.7%→593.3%→351.0%，連續 3 年遠超 100% 基準線。2024 年比值達 593%，主因 NI 大幅縮水至 1.22 億（較 2023 年 1.95 億 -37.6%），分母縮小導致比值極度膨脹。</li><li><strong>深度見解</strong>：CFO 本身穩定在 5.2-7.2 億區間（2025 年 6.64 億，2024 年 7.22 億），反映本業現金產出能力穩健。但 NI 波動劇烈——2023 年 1.95 億→2024 年 1.22 億→2025 年 1.89 億。NI 波動並非來自營收（3.52 億→4.15 億→4.11 億相當穩定），而是營益率從 15.0% 下滑至 11.4% 及非營業項目波動。2024 年營業費用暴增至 1.94 億（Q4 單季）、較 2023 年 Q4 的 1.37 億 +41%，是最主要的獲利侵蝕因子。</li></ul><h3 id="二、非現金項目分析-折舊掩蓋診斷" tabindex="-1">二、非現金項目分析（折舊掩蓋診斷） <a class="header-anchor" href="#二、非現金項目分析-折舊掩蓋診斷" aria-label="Permalink to &quot;二、非現金項目分析（折舊掩蓋診斷）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024 年折舊 5.02 億 + 攤銷 0.15 億 = 5.17 億，扣除折舊攤銷後 CFO 實際來自營運資金變動約 2.05 億。折舊佔 CFO 比重約 72%，顯示獲利高度依賴折舊加回。</li><li><strong>深度見解</strong>：折舊高達 5 億/年反映久元為資本密集型企業（測試設備、切割機台等資產龐大）。扣除折舊後實質營運現金流入僅 2 億左右，屬行業特性而非警訊。需關注的是：重資產折舊完畢後若無更新投資，CFO 將隨折舊逐年遞減而縮水。</li></ul><h3 id="三、fcf-與資本配置壓力測試" tabindex="-1">三、FCF 與資本配置壓力測試 <a class="header-anchor" href="#三、fcf-與資本配置壓力測試" aria-label="Permalink to &quot;三、FCF 與資本配置壓力測試&quot;">​</a></h3><ul><li><strong>核心重點</strong>：FCF 由 2023 年 3.88 億（強）→2024 年 2.39 億（中）→2025 年 -4.05 億（轉負）。2025 年 CapEx 約 10.7 億（CFO 6.64 億完全無法覆蓋，缺口 4.05 億）。</li><li><strong>深度見解</strong>：2025 年大額資本支出可能與自有產品設備擴產有關。若這些 CapEx 能在 2026-2027 年轉化為營收增長，則 FCF 轉負屬階段性投資；反之若 CapEx 效率不彰，將持續壓縮自由現金流，最終影響股利發放能力。</li></ul><h2 id="💡-專家評析-286-字" tabindex="-1">💡 專家評析（286 字） <a class="header-anchor" href="#💡-專家評析-286-字" aria-label="Permalink to &quot;💡 專家評析（286 字）&quot;">​</a></h2><ol><li><strong>營益率持續下滑壓縮 NI（利空）</strong>：營益率 15.0%→11.6%→11.4% 連續 3 年下跌，2024 年更因營業費用擴增 41% 侵蝕核心獲利。若營收成長停滯（2025 年已 -0.9%），費用率將持續上升，NI 存在進一步下滑風險。NI 從 1.95 億跌至 1.22 億幅度 -37.6%，即使 CFO 強勁，低 NI 將壓縮 EPS 與股東報酬。</li><li><strong>FCF 轉負壓力（警訊）</strong>：2025 年 FCF 由正轉負（-4.05 億），為近 4 年首見。CapEx 10.7 億全賴 CFO 6.64 億支應不足，尚需融資或舉債。若 CapEx 回收週期長，股利防禦能力將受考驗。</li><li><strong>折舊依賴度過高（風險）</strong>：CFO 中折舊加回佔比達 72%，代表本業營運資金產生的實質現金流僅約 2 億。雖屬行業常態，但若未來營收衰退（代工業務僅 +4% 到 24 億），折舊將從緩衝變成淨現金流出壓力源。2025 年存貨再增 5.1 億（現金流出），營運週轉效率有下滑跡象。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (cashflow_quality 6261)</li><li>原始數據：FinMind TaiwanStockCashFlowsStatement, FinMind TaiwanStockFinancialStatements</li><li>查詢參數：stock_id=6261, 年報 2024 合併財報現金流量表（第 12 頁）</li><li>數據查詢日期：2026-05-11</li></ul>',19)])])}const u=t(r,[["render",e]]);export{_ as __pageData,u as default};
